/** Hash-based routing (no react-router dependency) */
function parseHash() {
  const raw = (window.location.hash || '#/').replace(/^#/, '') || '/';
  const path = raw.startsWith('/') ? raw : `/${raw}`;
  const parts = path.split('/').filter(Boolean);
  if (parts.length === 0) return { name: 'home', params: {} };
  const [a, b, c] = parts;
  if (a === 'story' && b) return { name: 'story', params: { id: b } };
  if (a === 'bible') return { name: 'bible', params: { book: b || null, chapter: c || null } };
  if (a === 'maps') return { name: 'maps', params: {} };
  if (a === 'places') return { name: 'places', params: { place: b || null } };
  if (a === 'weather') return { name: 'weather', params: {} };
  if (a === 'games') return { name: 'games', params: {} };
  if (a === 'tools') return { name: 'tools', params: {} };
  if (a === 'gallery') return { name: 'gallery', params: {} };
  if (a === 'library') return { name: 'library', params: {} };
  if (a === 'life') return { name: 'life', params: { niche: b || null } };
  if (a === 'division' && b) return { name: 'division', params: { division: b } };
  return { name: 'home', params: {} };
}

function navigateHash(path) {
  const next = path.startsWith('#') ? path : `#${path.startsWith('/') ? path : `/${path}`}`;
  if (window.location.hash === next) {
    window.dispatchEvent(new Event('hashchange'));
  } else {
    window.location.hash = next;
  }
}

