function getPalette(book, division) {
  return BOOK_PALETTE[book] || BOOK_PALETTE[division] || BOOK_PALETTE.general;
}

const generatedArtCache = {};
function escapeSvgText(value = "") {
  return String(value).replace(/[&<>"]/g, ch => ({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;"}[ch]));
}
function wrapArtText(value = "", max = 34, lines = 3) {
  const words = String(value).split(/\s+/); const out = []; let line = "";
  words.forEach(word => {
    const next = line ? line + " " + word : word;
    if (next.length > max && line) { out.push(line); line = word; } else line = next;
  });
  if (line) out.push(line);
  return out.slice(0, lines);
}
function generatedStoryArt(story, width = 1200, height = 675) {
  return resolveStoryImage(story, width, height) || generatedStoryArtFromLib(story, width, height);
}


