    function BibleReader({ onClose, initialBook = null, initialChapter = null, initialVerse = null }) {
      let savedVersion = "en-kjv", savedBook = "john", savedChapter = 1;
      try {
        savedVersion = localStorage.getItem("vn-bible-version") || "en-kjv";
        savedBook = localStorage.getItem("vn-bible-book") || "john";
        savedChapter = Number(localStorage.getItem("vn-bible-chapter") || 1);
      } catch (_) {}
      const [version, setVersion] = useState(BIBLE_PRESETS.some(v => v.id === savedVersion) ? savedVersion : "en-kjv");
      const [book, setBook] = useState(initialBook || savedBook);
      const [chapter, setChapter] = useState(Number(initialChapter || savedChapter || 1));
      const [verses, setVerses] = useState([]);
      const [loadingBible, setLoadingBible] = useState(true);
      const [error, setError] = useState("");
      const selectedBook = BIBLE_BOOKS.find(b => b[0] === book) || BIBLE_BOOKS[0];

      useEffect(() => {
        try {
          localStorage.setItem("vn-bible-version", version);
          localStorage.setItem("vn-bible-book", book);
          localStorage.setItem("vn-bible-chapter", String(chapter));
        } catch (_) {}
        setLoadingBible(true); setError(""); setVerses([]);
        const url = `https://cdn.jsdelivr.net/gh/wldeh/bible-api/bibles/${version}/books/${book}/chapters/${chapter}.json`;
        fetch(url)
          .then(r => { if (!r.ok) throw new Error("This translation does not contain that chapter."); return r.json(); })
          .then(data => {
            const raw = Array.isArray(data) ? data : (data.verses || data.data || data.chapter || []);
            const normalized = Array.isArray(raw) ? raw.map((v, i) => ({
              number: v.verse || v.verseNumber || v.number || i + 1,
              text: v.text || v.content || v.verseText || (typeof v === "string" ? v : "")
            })).filter(v => v.text) : [];
            if (!normalized.length && data.text) normalized.push({number:1,text:data.text});
            if (!normalized.length) throw new Error("No readable text was returned for this chapter.");
            setVerses(normalized);
          })
          .catch(e => setError(e.message || "Unable to load this chapter. Check your internet connection or try KJV, WEB, YLT, or BBE."))
          .finally(() => setLoadingBible(false));
      }, [version, book, chapter]);

      useEffect(() => { if (!initialBook || book !== initialBook) setChapter(1); }, [book]);

      useEffect(() => {
        if (!loadingBible && !error && initialVerse && verses.length) {
          requestAnimationFrame(() => document.getElementById(`bible-verse-${initialVerse}`)?.scrollIntoView({behavior:"smooth", block:"center"}));
        }
      }, [loadingBible, error, initialVerse, verses]);

      const selectedVersion = BIBLE_PRESETS.find(v => v.id === version) || BIBLE_PRESETS[0];

      const moveChapter = delta => {
        let idx = BIBLE_BOOKS.findIndex(b => b[0] === book), nextChapter = chapter + delta;
        if (nextChapter < 1 && idx > 0) { idx -= 1; setBook(BIBLE_BOOKS[idx][0]); setChapter(BIBLE_BOOKS[idx][2]); }
        else if (nextChapter > selectedBook[2] && idx < BIBLE_BOOKS.length - 1) { idx += 1; setBook(BIBLE_BOOKS[idx][0]); setChapter(1); }
        else if (nextChapter >= 1 && nextChapter <= selectedBook[2]) setChapter(nextChapter);
      };
      return (
        <main className="bible-page" style={{maxWidth:1200,margin:"0 auto",padding:"28px 20px 60px"}}>
          <div style={{display:"flex",justifyContent:"space-between",gap:20,alignItems:"flex-start",marginBottom:22}}>
            <div><div style={{font:"900 11px Arial,sans-serif",letterSpacing:2,color:VN_RED}}>FULL BIBLE READER</div><h1 style={{font:"700 clamp(32px,5vw,58px) Georgia,serif",margin:"6px 0"}}>Read the Bible</h1><p style={{font:"15px Arial,sans-serif",color:VN_MUTED,maxWidth:720,lineHeight:1.6}}>Choose a translation, book, and chapter. The reader includes KJV, WEB, YLT, and BBE.</p></div>
            <button onClick={onClose} style={{border:"1px solid #bbb",background:"#fff",padding:"10px 14px",font:"800 11px Arial,sans-serif",cursor:"pointer"}}>← BACK TO NEWS</button>
          </div>

          <section style={{background:"#fff",border:"1px solid #d9d9d2",padding:18,boxShadow:"0 8px 24px rgba(0,0,0,.06)",marginBottom:22}}>
            <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(180px,1fr))",gap:12}}>
              <label style={{font:"800 10px Arial,sans-serif",letterSpacing:1}}>TRANSLATION<select value={version} onChange={e=>setVersion(e.target.value)} style={{width:"100%",marginTop:7,padding:11,border:"1px solid #bbb",background:"#fff"}}>{BIBLE_PRESETS.map(v=><option key={v.id} value={v.id}>{v.name}</option>)}</select></label>
              <label style={{font:"800 10px Arial,sans-serif",letterSpacing:1}}>BOOK<select value={book} onChange={e=>setBook(e.target.value)} style={{width:"100%",marginTop:7,padding:11,border:"1px solid #bbb",background:"#fff"}}>{["Old Testament","New Testament"].map(t=><optgroup key={t} label={t}>{BIBLE_BOOKS.filter(b=>b[3]===t).map(b=><option key={b[0]} value={b[0]}>{b[1]}</option>)}</optgroup>)}</select></label>
              <label style={{font:"800 10px Arial,sans-serif",letterSpacing:1}}>CHAPTER<select value={chapter} onChange={e=>setChapter(Number(e.target.value))} style={{width:"100%",marginTop:7,padding:11,border:"1px solid #bbb",background:"#fff"}}>{Array.from({length:selectedBook[2]},(_,i)=><option key={i+1} value={i+1}>{i+1}</option>)}</select></label>
            </div>
            <div style={{marginTop:12,font:"12px Arial,sans-serif",color:VN_MUTED}}>Selected: <strong>{selectedVersion.name}</strong> · {selectedVersion.license}</div>
          </section>

          <article style={{background:"#fff",borderTop:`5px solid ${VN_RED}`,padding:"clamp(20px,4vw,48px)",boxShadow:"0 10px 30px rgba(0,0,0,.07)"}}>
            <div style={{display:"flex",justifyContent:"space-between",gap:15,alignItems:"center",borderBottom:"1px solid #ddd",paddingBottom:18,marginBottom:24}}>
              <button onClick={()=>moveChapter(-1)} disabled={book===BIBLE_BOOKS[0][0]&&chapter===1} style={{padding:"9px 12px",border:"1px solid #bbb",background:"#fff",cursor:"pointer"}}>← Previous</button>
              <div style={{textAlign:"center"}}><h2 style={{font:"700 clamp(28px,4vw,44px) Georgia,serif",margin:0}}>{selectedBook[1]} {chapter}</h2><div style={{font:"11px Arial,sans-serif",color:VN_MUTED,marginTop:5}}>{selectedVersion.name}</div></div>
              <button onClick={()=>moveChapter(1)} disabled={book===BIBLE_BOOKS[BIBLE_BOOKS.length-1][0]&&chapter===22} style={{padding:"9px 12px",border:"1px solid #bbb",background:"#fff",cursor:"pointer"}}>Next →</button>
            </div>
            {loadingBible && <div style={{padding:50,textAlign:"center",font:"14px Arial,sans-serif",color:VN_MUTED}}>Loading chapter…</div>}
            {error && <div style={{padding:24,background:"#fff4f4",border:"1px solid #e7b4b4",font:"14px Arial,sans-serif",lineHeight:1.6}}><strong>Chapter unavailable.</strong><br/>{error}<br/><br/>Try WEB, KJV, or ASV, which are included as dependable open presets.</div>}
            {!loadingBible && !error && <div style={{maxWidth:820,margin:"0 auto"}}>{verses.map(v=>{const isTarget=String(v.number)===String(initialVerse);return <p id={`bible-verse-${v.number}`} key={v.number} style={{font:"19px/1.85 Georgia,serif",margin:"0 0 13px",color:"#171717",background:isTarget?"#fff3bf":"transparent",borderLeft:isTarget?`4px solid ${VN_RED}`:"4px solid transparent",padding:isTarget?"10px 12px":"0 12px",scrollMarginTop:120,fontWeight:isTarget?700:400,transition:"background .3s ease"}}><sup style={{font:"800 10px Arial,sans-serif",color:VN_RED,marginRight:7}}>{v.number}</sup>{v.text}</p>})}</div>}
          </article>
        </main>
      );
    }



    const BIBLICAL_PLACES = [{"id":"eden","name":"Garden of Eden","region":"Primeval World","era":"Creation","testament":"Old Testament","country":"Ancient Mesopotamia","coords":[91,49],"summary":"The garden where humanity first lived in fellowship with God before the fall.","refs":["Genesis 2–3"],"keywords":["Eden","Garden"],"facts":["Adam and Eve were placed here.","The tree of life and tree of knowledge stood here."]},{"id":"ararat","name":"Mount Ararat","region":"Armenian Highlands","era":"Flood","testament":"Old Testament","country":"Türkiye","coords":[72,5],"summary":"The mountain region where Noah’s ark came to rest after the flood.","refs":["Genesis 8:4"],"keywords":["Ararat","Noah"],"facts":["The ark rested in this region.","The location became a symbol of preservation and new beginnings."]},{"id":"babel","name":"Babel","region":"Shinar","era":"Primeval History","testament":"Old Testament","country":"Iraq","coords":[93,42],"summary":"The city and tower associated with humanity’s scattered languages.","refs":["Genesis 11:1–9"],"keywords":["Babel","Tower"],"facts":["The people sought to make a name for themselves.","God confused their language and scattered them."]},{"id":"ur","name":"Ur","region":"Mesopotamia","era":"Patriarchs","testament":"Old Testament","country":"Iraq","coords":[95,53],"summary":"Abram’s ancestral city before his family journeyed toward Canaan.","refs":["Genesis 11:28–31"],"keywords":["Ur","Abram"],"facts":["Terah’s family departed from Ur.","It was a major ancient Mesopotamian center."]},{"id":"haran","name":"Haran","region":"Upper Mesopotamia","era":"Patriarchs","testament":"Old Testament","country":"Türkiye","coords":[69,12],"summary":"The city where Abram’s family settled before his call to Canaan.","refs":["Genesis 11:31–12:5"],"keywords":["Haran","Abram","Jacob"],"facts":["Abram departed from here at age seventy-five.","Jacob later lived with Laban in this region."]},{"id":"shechem","name":"Shechem","region":"Samaria","era":"Patriarchs to Kingdom","testament":"Old Testament","country":"West Bank","coords":[60,39],"summary":"A covenant landmark tied to Abraham, Jacob, Joshua, and the divided kingdom.","refs":["Genesis 12:6","Joshua 24","1 Kings 12"],"keywords":["Shechem"],"facts":["Abram built an altar nearby.","Joshua renewed Israel’s covenant here."]},{"id":"bethel","name":"Bethel","region":"Central Highlands","era":"Patriarchs to Kingdom","testament":"Old Testament","country":"West Bank","coords":[61,44],"summary":"A major worship site associated with Jacob’s dream and later kingdom-era idolatry.","refs":["Genesis 28","1 Kings 12:28–33"],"keywords":["Bethel","Jacob"],"facts":["Jacob saw the stairway to heaven here.","Jeroboam established a rival shrine here."]},{"id":"hebron","name":"Hebron","region":"Judea","era":"Patriarchs to Kingdom","testament":"Old Testament","country":"West Bank","coords":[57,62],"summary":"A patriarchal center, burial place of the ancestors, and David’s first capital.","refs":["Genesis 23","2 Samuel 2:1–4"],"keywords":["Hebron","Machpelah","David"],"facts":["Abraham purchased the cave of Machpelah.","David ruled here before taking Jerusalem."]},{"id":"goshen","name":"Goshen","region":"Nile Delta","era":"Exodus","testament":"Old Testament","country":"Egypt","coords":[43,69],"summary":"The fertile Egyptian region where Jacob’s family settled and Israel multiplied.","refs":["Genesis 46–47","Exodus 8:22"],"keywords":["Goshen","Egypt"],"facts":["Joseph settled his family here.","The land was distinguished during several plagues."]},{"id":"rameses","name":"Rameses","region":"Nile Delta","era":"Exodus","testament":"Old Testament","country":"Egypt","coords":[40,67],"summary":"A store-city region associated with Israelite labor and the beginning of the Exodus.","refs":["Exodus 1:11","Exodus 12:37"],"keywords":["Rameses","Egypt"],"facts":["Israelites built store cities in this region.","The departure from Egypt began here."]},{"id":"succoth","name":"Succoth","region":"Eastern Nile Delta","era":"Exodus","testament":"Old Testament","country":"Egypt","coords":[47,70],"summary":"An early encampment on Israel’s route out of Egypt.","refs":["Exodus 12:37","Numbers 33:5"],"keywords":["Succoth","Exodus"],"facts":["Israel camped here after leaving Rameses.","It marked the first stage of the Exodus journey."]},{"id":"marah","name":"Marah","region":"Sinai Wilderness","era":"Exodus","testament":"Old Testament","country":"Egypt","coords":[51,78],"summary":"A wilderness stop where bitter water was made drinkable.","refs":["Exodus 15:22–25"],"keywords":["Marah","Exodus"],"facts":["The people complained about bitter water.","Moses was shown how to make it sweet."]},{"id":"elim","name":"Elim","region":"Sinai Wilderness","era":"Exodus","testament":"Old Testament","country":"Egypt","coords":[53,80],"summary":"A desert oasis with twelve springs and seventy palm trees.","refs":["Exodus 15:27"],"keywords":["Elim","Exodus"],"facts":["Israel camped beside abundant water.","Its twelve springs echoed Israel’s twelve tribes."]},{"id":"sinai","name":"Mount Sinai","region":"Sinai Wilderness","era":"Exodus","testament":"Old Testament","country":"Egypt","coords":[54,84],"summary":"The mountain where Israel entered covenant with God and received the commandments.","refs":["Exodus 19–34"],"keywords":["Mount Sinai","Sinai","Exodus"],"facts":["The mountain was covered with smoke and fire.","Moses received the covenant law here."]},{"id":"kadesh","name":"Kadesh Barnea","region":"Negev Wilderness","era":"Wilderness","testament":"Old Testament","country":"Israel","coords":[51,72],"summary":"A critical wilderness encampment linked to the spies and Israel’s prolonged wandering.","refs":["Numbers 13–14","Numbers 20"],"keywords":["Kadesh","Kadesh Barnea"],"facts":["The spies were sent from this region.","Miriam died nearby."]},{"id":"jericho","name":"Jericho","region":"Jordan Valley","era":"Conquest to Gospels","testament":"Both","country":"West Bank","coords":[68,52],"summary":"A strategic oasis city known for Israel’s first conquest victory and events in Jesus’ ministry.","refs":["Joshua 6","Luke 19"],"keywords":["Jericho","Jordan River"],"facts":["Its walls fell after Israel’s procession.","Jesus met Zacchaeus here."]},{"id":"ai","name":"Ai","region":"Central Highlands","era":"Conquest","testament":"Old Testament","country":"West Bank","coords":[64,45],"summary":"A Canaanite city where Israel suffered an initial defeat before victory.","refs":["Joshua 7–8"],"keywords":["Ai","Joshua"],"facts":["Achan’s sin preceded Israel’s defeat.","Joshua later captured the city through ambush."]},{"id":"gilgal","name":"Gilgal","region":"Jordan Valley","era":"Conquest","testament":"Old Testament","country":"West Bank","coords":[67,49],"summary":"Israel’s first major camp west of the Jordan and a base during the conquest.","refs":["Joshua 4–5","1 Samuel 11"],"keywords":["Gilgal"],"facts":["Twelve memorial stones were set up here.","Saul’s kingship was renewed here."]},{"id":"shiloh","name":"Shiloh","region":"Ephraim","era":"Judges to Samuel","testament":"Old Testament","country":"West Bank","coords":[61,37],"summary":"The early sanctuary site where the tabernacle and ark were located.","refs":["Joshua 18:1","1 Samuel 1–4"],"keywords":["Shiloh","Samuel","Eli"],"facts":["The tabernacle stood here.","Samuel served under Eli here."]},{"id":"gibeon","name":"Gibeon","region":"Benjamin","era":"Conquest to Kingdom","testament":"Old Testament","country":"West Bank","coords":[60,47],"summary":"A city known for its treaty with Israel and Solomon’s great dream.","refs":["Joshua 9–10","1 Kings 3"],"keywords":["Gibeon","Solomon"],"facts":["The Gibeonites secured a treaty through deception.","Solomon asked God for wisdom here."]},{"id":"mizpah","name":"Mizpah","region":"Benjamin","era":"Judges to Samuel","testament":"Old Testament","country":"West Bank","coords":[62,45],"summary":"An assembly and judgment site during the judges and Samuel’s leadership.","refs":["Judges 20","1 Samuel 7"],"keywords":["Mizpah","Samuel"],"facts":["Israel gathered here for national decisions.","Samuel led repentance and intercession here."]},{"id":"jerusalem","name":"Jerusalem","region":"Judea","era":"Kingdom to Early Church","testament":"Both","country":"Israel","coords":[61,49],"summary":"Israel’s royal and spiritual center; site of the temple, crucifixion, resurrection, and Pentecost.","refs":["2 Samuel 5","1 Kings 8","Luke 23–24","Acts 2"],"keywords":["Jerusalem","Temple Mount","Zion"],"facts":["David established Jerusalem as his capital.","The earliest church witnessed here."]},{"id":"bethlehem","name":"Bethlehem","region":"Judea","era":"Judges to Gospels","testament":"Both","country":"West Bank","coords":[58,57],"summary":"The town of Ruth and David, later identified as the birthplace of Jesus.","refs":["Ruth 1–4","1 Samuel 16","Luke 2"],"keywords":["Bethlehem","David"],"facts":["David was born and anointed here.","Jesus was born here."]},{"id":"gibeah","name":"Gibeah","region":"Benjamin","era":"Judges to Kingdom","testament":"Old Testament","country":"West Bank","coords":[61,46],"summary":"A Benjaminite town associated with tribal conflict and King Saul.","refs":["Judges 19–20","1 Samuel 10"],"keywords":["Gibeah","Saul"],"facts":["The crime at Gibeah triggered civil war.","Saul ruled from this region."]},{"id":"carmel","name":"Mount Carmel","region":"Northern Israel","era":"Kingdom","testament":"Old Testament","country":"Israel","coords":[52,24],"summary":"The mountain where Elijah challenged the prophets of Baal.","refs":["1 Kings 18"],"keywords":["Mount Carmel","Elijah"],"facts":["Elijah called down fire here.","The drought ended shortly afterward."]},{"id":"jezreel","name":"Jezreel","region":"Jezreel Valley","era":"Kingdom","testament":"Old Testament","country":"Israel","coords":[61,25],"summary":"A royal center associated with Ahab, Jezebel, Naboth, and Jehu.","refs":["1 Kings 21","2 Kings 9"],"keywords":["Jezreel","Ahab","Jezebel"],"facts":["Naboth’s vineyard was here.","Jehu’s revolt reached its climax here."]},{"id":"samaria","name":"Samaria","region":"Northern Kingdom","era":"Divided Kingdom","testament":"Old Testament","country":"West Bank","coords":[59,34],"summary":"The capital of the northern kingdom of Israel.","refs":["1 Kings 16:24","2 Kings 6–7"],"keywords":["Samaria","Israel"],"facts":["Omri established the capital here.","The city endured major sieges."]},{"id":"dan","name":"Dan","region":"Northern Israel","era":"Judges to Kingdom","testament":"Old Testament","country":"Israel","coords":[68,13],"summary":"A northern boundary city and later center of rival worship.","refs":["Judges 18","1 Kings 12:29"],"keywords":["Dan"],"facts":["The tribe of Dan captured the city.","Jeroboam placed a golden calf here."]},{"id":"beersheba","name":"Beersheba","region":"Negev","era":"Patriarchs to Kingdom","testament":"Old Testament","country":"Israel","coords":[55,69],"summary":"A southern settlement tied to Abraham, Isaac, Jacob, and Elijah.","refs":["Genesis 21","Genesis 26","1 Kings 19"],"keywords":["Beersheba"],"facts":["Abraham made a covenant here.","Elijah fled through Beersheba."]},{"id":"lachish","name":"Lachish","region":"Shephelah","era":"Kingdom","testament":"Old Testament","country":"Israel","coords":[50,58],"summary":"A fortified Judahite city attacked by Assyria and later Babylon.","refs":["2 Kings 18","Jeremiah 34:7"],"keywords":["Lachish","Assyria"],"facts":["Sennacherib besieged the city.","Archaeological reliefs depict its fall."]},{"id":"megiddo","name":"Megiddo","region":"Jezreel Valley","era":"Conquest to Kingdom","testament":"Old Testament","country":"Israel","coords":[58,23],"summary":"A strategic fortified city overlooking major trade routes.","refs":["Joshua 17","2 Kings 23:29"],"keywords":["Megiddo"],"facts":["Solomon fortified the city.","King Josiah died nearby."]},{"id":"nineveh","name":"Nineveh","region":"Assyria","era":"Prophets","testament":"Old Testament","country":"Iraq","coords":[94,18],"summary":"The Assyrian capital to which Jonah was sent to preach repentance.","refs":["Jonah 1–4","Nahum 1–3"],"keywords":["Nineveh","Jonah"],"facts":["Jonah preached here.","Nahum later announced the city’s fall."]},{"id":"babylon","name":"Babylon","region":"Mesopotamia","era":"Exile","testament":"Old Testament","country":"Iraq","coords":[94,43],"summary":"The imperial city that conquered Judah and became the principal setting of exile narratives.","refs":["2 Kings 24–25","Daniel 1–6"],"keywords":["Babylon","Daniel","Exile"],"facts":["Jerusalem’s elite were deported here.","Daniel served under successive rulers."]},{"id":"susa","name":"Susa","region":"Persian Empire","era":"Exile and Return","testament":"Old Testament","country":"Iran","coords":[99,47],"summary":"A Persian royal city central to the story of Esther and Nehemiah.","refs":["Esther 1–10","Nehemiah 1"],"keywords":["Susa","Esther","Nehemiah"],"facts":["Esther became queen here.","Nehemiah served the Persian king here."]},{"id":"nazareth","name":"Nazareth","region":"Galilee","era":"Gospels","testament":"New Testament","country":"Israel","coords":[58,28],"summary":"The Galilean hometown where Jesus grew up and later taught in the synagogue.","refs":["Matthew 2:23","Luke 4:16–30"],"keywords":["Nazareth","Galilee"],"facts":["Jesus was raised here.","His hometown synagogue rejected him."]},{"id":"capernaum","name":"Capernaum","region":"Galilee","era":"Gospels","testament":"New Testament","country":"Israel","coords":[69,21],"summary":"A lakeside center of Jesus’ Galilean ministry.","refs":["Matthew 4:13","Mark 1–2","John 6"],"keywords":["Capernaum","Sea of Galilee"],"facts":["Jesus taught in its synagogue.","Peter’s household was located here."]},{"id":"cana","name":"Cana","region":"Galilee","era":"Gospels","testament":"New Testament","country":"Israel","coords":[61,26],"summary":"A Galilean village associated with Jesus’ first sign.","refs":["John 2:1–11","John 4:46"],"keywords":["Cana","Wedding"],"facts":["Jesus turned water into wine here.","A royal official sought healing here."]},{"id":"bethany","name":"Bethany","region":"Judea","era":"Gospels","testament":"New Testament","country":"West Bank","coords":[64,51],"summary":"The village of Mary, Martha, and Lazarus near Jerusalem.","refs":["John 11–12","Luke 10:38–42"],"keywords":["Bethany","Lazarus"],"facts":["Lazarus was raised here.","Jesus was welcomed in the home of friends."]},{"id":"bethsaida","name":"Bethsaida","region":"Galilee","era":"Gospels","testament":"New Testament","country":"Israel","coords":[71,20],"summary":"A fishing town associated with several disciples and miracles.","refs":["Mark 8:22–26","John 1:44"],"keywords":["Bethsaida","Philip","Andrew"],"facts":["Philip, Andrew, and Peter were linked to the town.","Jesus healed a blind man here."]},{"id":"chorazin","name":"Chorazin","region":"Galilee","era":"Gospels","testament":"New Testament","country":"Israel","coords":[67,18],"summary":"A Galilean town rebuked by Jesus for unbelief despite mighty works.","refs":["Matthew 11:21","Luke 10:13"],"keywords":["Chorazin"],"facts":["Jesus performed works here.","The town was warned for failing to repent."]},{"id":"magdala","name":"Magdala","region":"Galilee","era":"Gospels","testament":"New Testament","country":"Israel","coords":[64,24],"summary":"A town on the Sea of Galilee associated by name with Mary Magdalene.","refs":["Matthew 15:39","Luke 8:2"],"keywords":["Magdala","Mary Magdalene"],"facts":["Mary Magdalene’s name reflects association with Magdala.","The town stood on a major lakeside route."]},{"id":"damascus","name":"Damascus","region":"Syria","era":"Early Church","testament":"New Testament","country":"Syria","coords":[82,13],"summary":"An ancient city closely associated with Paul’s conversion and earliest preaching.","refs":["Acts 9"],"keywords":["Damascus","Paul","Saul"],"facts":["Saul encountered Jesus on the road here.","He preached in the city soon afterward."]},{"id":"antioch","name":"Antioch","region":"Syria","era":"Early Church","testament":"New Testament","country":"Türkiye","coords":[58,8],"summary":"A major early-Christian center where believers were first called Christians.","refs":["Acts 11:19–30","Acts 13:1–3"],"keywords":["Antioch","Paul","Barnabas"],"facts":["A diverse church flourished here.","Paul and Barnabas were commissioned here."]},{"id":"tarsus","name":"Tarsus","region":"Cilicia","era":"Early Church","testament":"New Testament","country":"Türkiye","coords":[52,15],"summary":"Paul’s native city in Cilicia.","refs":["Acts 9:11","Acts 21:39","Acts 22:3"],"keywords":["Tarsus","Paul"],"facts":["Paul was born here.","Barnabas later brought Paul from Tarsus to Antioch."]},{"id":"ephesus","name":"Ephesus","region":"Asia Minor","era":"Early Church","testament":"New Testament","country":"Türkiye","coords":[30,29],"summary":"A prominent Roman city where Paul ministered extensively.","refs":["Acts 18–20","Ephesians 1"],"keywords":["Ephesus","Paul","Artemis"],"facts":["Paul taught here for an extended period.","The gospel disrupted the idol-making economy."]},{"id":"corinth","name":"Corinth","region":"Achaia","era":"Early Church","testament":"New Testament","country":"Greece","coords":[21,49],"summary":"A wealthy port city where Paul established a church.","refs":["Acts 18","1 Corinthians 1"],"keywords":["Corinth","Paul"],"facts":["Paul stayed for eighteen months.","Two New Testament letters address this church."]},{"id":"philippi","name":"Philippi","region":"Macedonia","era":"Early Church","testament":"New Testament","country":"Greece","coords":[28,35],"summary":"The first major European city where Paul established a congregation.","refs":["Acts 16","Philippians 1"],"keywords":["Philippi","Lydia","Paul"],"facts":["Lydia believed here.","Paul and Silas were imprisoned here."]},{"id":"thessalonica","name":"Thessalonica","region":"Macedonia","era":"Early Church","testament":"New Testament","country":"Greece","coords":[25,38],"summary":"A Macedonian city where Paul preached and formed a church.","refs":["Acts 17","1 Thessalonians 1"],"keywords":["Thessalonica","Paul"],"facts":["Paul reasoned in the synagogue here.","The church endured persecution."]},{"id":"athens","name":"Athens","region":"Achaia","era":"Early Church","testament":"New Testament","country":"Greece","coords":[22,47],"summary":"The intellectual center where Paul addressed the Areopagus.","refs":["Acts 17:16–34"],"keywords":["Athens","Areopagus","Paul"],"facts":["Paul spoke about the unknown god.","Dionysius and Damaris believed."]},{"id":"malta","name":"Malta","region":"Mediterranean","era":"Early Church","testament":"New Testament","country":"Malta","coords":[13,57],"summary":"The island where Paul survived shipwreck and ministered before reaching Rome.","refs":["Acts 27–28"],"keywords":["Malta","Paul","Shipwreck"],"facts":["Paul survived a viper bite here.","The islanders received healing ministry."]}];

